// lib/i18n/i18n.ts
var messages = {
  en: en_default,
  es: es_default,
  ja: ja_default,
  zh: zh_default
};
function translate(locale, key, values) {
  const t2 = createTranslator({ locale, messages: messages[locale] });
  return t2(key, values);
}

// lib/database/i18n.ts
function translateDatabase(key, values, options) {
  const locale = options?.locale || "en";
  return translate(locale, key, values);
}

