// lib/database/pglite/pg-version.ts
import fs3 from "node:fs/promises";
import path3 from "node:path";
async function readPgVersion(dataDir) {
  try {
    const content = await fs3.readFile(path3.join(dataDir, "PG_VERSION"), "utf8");
    const version2 = parseInt(content.trim(), 10);
    return Number.isFinite(version2) ? version2 : null;
  } catch {
    return null;
  }
}
var CURRENT_PG_VERSION = 17;

// lib/database/pglite/pg-version-migration.ts
function createArchiveSuffix(date2 = new Date) {
  const pad = (value) => String(value).padStart(2, "0");
  return [
    date2.getFullYear(),
    pad(date2.getMonth() + 1),
    pad(date2.getDate()),
    "-",
    pad(date2.getHours()),
    pad(date2.getMinutes()),
    pad(date2.getSeconds())
  ].join("");
}
async function migrateFromPg16IfNeeded(dataDir) {
  const pgVersion = await readPgVersion(dataDir);
  if (pgVersion === null || pgVersion >= CURRENT_PG_VERSION) {
    return { migrated: false, snapshot: null, archivedDataDir: null };
  }
  console.log(`[PGlite upgrade] Detected PG ${pgVersion} data, migrating to PG ${CURRENT_PG_VERSION}...`);
  const archivedDataDir = path4.join(path4.dirname(dataDir), `${path4.basename(dataDir)}.pg${pgVersion}-upgrade-${createArchiveSuffix()}`);
  await fs4.rename(dataDir, archivedDataDir);
  console.log("[PGlite upgrade] Archived old data directory", {
    from: dataDir,
    to: archivedDataDir
  });
  const snapshotPath = `${archivedDataDir}.upgrade-snapshot.json`;
  let snapshot = null;
  try {
    snapshot = await exportWorkspaceRecoverySnapshot(archivedDataDir, snapshotPath, Ue5);
    console.log("[PGlite upgrade] Successfully exported data from old database");
  } catch (error2) {
    console.error("[PGlite upgrade] Failed to export data from old database. " + "The archived directory is preserved for manual recovery.", {
      error: error2,
      archivedDataDir
    });
  }
  return { migrated: true, snapshot, archivedDataDir };
}

// lib/database/pglite/migrate-pglite.ts
async function runDrizzleMigrate(db) {
  const dialect = db?.dialect;
  const session2 = db?.session;
  if (!dialect || typeof dialect.migrate !== "function" || !session2) {
    throw new Error(translateDatabase("Database.Errors.PgliteInvalidInstance"));
  }
  await dialect.migrate(migrations_default, session2, {
    migrationsTable: "drizzle_migrations"
  });
}
function createArchiveSuffix2(date2 = new Date) {
  const pad = (value) => String(value).padStart(2, "0");
  return [
    date2.getFullYear(),
    pad(date2.getMonth() + 1),
    pad(date2.getDate()),
    "-",
    pad(date2.getHours()),
    pad(date2.getMinutes()),
    pad(date2.getSeconds())
  ].join("");
}
async function archivePgliteDataDir(dataDir) {
  const archivedDataDir = path5.join(path5.dirname(dataDir), `${path5.basename(dataDir)}.broken-${createArchiveSuffix2()}`);
  await fs5.rename(dataDir, archivedDataDir);
  console.warn("[PGlite migrate] Archived broken data directory", {
    from: dataDir,
    to: archivedDataDir
  });
  return archivedDataDir;
}
async function migratePgliteDB() {
  const dataDir = await resolvePgliteDataDir();
  const upgradeResult = await migrateFromPg16IfNeeded(dataDir);
  const db = await getPgliteClient();
  try {
    await runDrizzleMigrate(db);
  } catch (err2) {
    console.warn(translateDatabase("Database.Errors.PgliteMigrationFailed"), {
      error: err2,
      message: err2 instanceof Error ? err2.message : String(err2),
      stack: err2 instanceof Error ? err2.stack : undefined,
      cause: err2 instanceof Error && "cause" in err2 ? err2.cause : undefined
    });
    try {
      await resetPgliteClient();
    } catch (resetError) {
      console.warn("[PGlite migrate] Failed to close crashed PGlite instance, proceeding with recovery", resetError);
    }
    const archivedDataDir = await archivePgliteDataDir(dataDir);
    const snapshotPath = `${archivedDataDir}.workspace-recovery.json`;
    let recoverySnapshot = null;
    try {
      recoverySnapshot = await exportWorkspaceRecoverySnapshot(archivedDataDir, snapshotPath);
    } catch (recoveryError) {
      console.warn("[PGlite migrate] Workspace recovery export failed", {
        archivedDataDir,
        snapshotPath,
        recoveryError
      });
    }
    const freshDb = await getPgliteClient();
    await runDrizzleMigrate(freshDb);
    if (recoverySnapshot) {
      try {
        await importWorkspaceRecoverySnapshot(freshDb, recoverySnapshot);
      } catch (recoveryError) {
        console.warn("[PGlite migrate] Workspace recovery import failed", {
          snapshotPath,
          recoveryError
        });
      }
    }
    return;
  }
  if (upgradeResult.migrated && upgradeResult.snapshot) {
    try {
      await importWorkspaceRecoverySnapshot(db, upgradeResult.snapshot);
      console.log("[PGlite upgrade] Successfully imported data into new PG 17 database");
    } catch (importError) {
      console.warn("[PGlite upgrade] Failed to import some data into new database", {
        importError
      });
    }
  }
}

// lib/database/provider.ts
var cachedProvider = null;
function getDatabaseProvider() {
  if (cachedProvider)
    return cachedProvider;
  const raw = (process.env.DB_TYPE ?? "pglite").toLowerCase();
  cachedProvider = raw === "pglite" ? "pglite" : "postgres";
  return cachedProvider;
}

// lib/demo/paths.ts
